// Validate + extract + generate report ID
const body = $input.first().json.body || $input.first().json;

const contact = body.contact || {};
const projectState = body.projectState || {};
const estimate = body.estimate || {};

// Validate required fields
if (!contact.name || !contact.phone || !contact.email) {
  throw new Error('Missing required contact fields: name, phone, email');
}
if (!body.calculator && !body.project_type) {
  // Infer calculator type from project state keys
  if (projectState.deck_size || projectState.deck_height || projectState.material) {
    body.calculator = 'deck';
  } else {
    body.calculator = 'bathroom';
  }
}

// Generate 8-char report ID
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let reportId = '';
for (let i = 0; i < 8; i++) reportId += chars[Math.floor(Math.random() * chars.length)];

// Parse name
const nameParts = contact.name.trim().split(/\s+/);
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

// Build calculator type label
const calcType = (body.calculator || 'bathroom');
const calcLabel = calcType === 'deck' ? 'Deck' : 'Bathroom';

// Format selections for JT job description
const stateEntries = Object.entries(projectState)
  .filter(([k]) => k !== 'features')
  .map(([k, v]) => `${k.replace(/_/g, ' ')}: ${String(v).replace(/_/g, ' ')}`)
  .join('\n');

const features = (projectState.features || []).join(', ').replace(/_/g, ' ');

const jobDescription = [
  `Calculator: ${calcLabel}`,
  `Estimate: $${(estimate.low || 0).toLocaleString()} – $${(estimate.high || 0).toLocaleString()}`,
  '',
  stateEntries,
  features ? `Features: ${features}` : '',
  '',
  contact.preferred_date ? `Preferred call: ${contact.preferred_date}, ${contact.preferred_time || 'any time'}` : '',
  contact.notes ? `Notes: ${contact.notes}` : '',
  '',
  `Report: https://heartwoodcraft.me/report/?id=${reportId}`
].filter(Boolean).join('\n');

return [{
  json: {
    // Original payload
    ...body,
    // Extracted fields
    report_id: reportId,
    calculator: calcType,
    calc_label: calcLabel,
    contact_name: contact.name,
    contact_phone: contact.phone,
    contact_email: contact.email,
    contact_notes: contact.notes || '',
    first_name: firstName,
    last_name: lastName,
    project_state: projectState,
    estimate_low: estimate.low || 0,
    estimate_high: estimate.high || 0,
    preferred_date: contact.preferred_date || null,
    preferred_time: contact.preferred_time || null,
    attribution: body.attribution || null,
    landing_page: body.landing_page || '',
    referrer: body.referrer || '',
    source_page: body.source_page || '',
    job_description: jobDescription,
    report_url: `https://heartwoodcraft.me/report/?id=${reportId}`,
    // For JT custom fields
    jt_source_value: 'Website Calculator',
    jt_job_type: calcLabel,
    jt_job_name: `${contact.name}'s ${calcLabel} Project`
  }
}];

const prev = $input.first().json;
let accountId;
try {
  const result = typeof prev.result === 'string' ? JSON.parse(prev.result) : prev.result;
  accountId = result?.createAccount?.id || result?.id;
} catch(e) {
  // Try to find ID in the response
  const str = JSON.stringify(prev);
  const match = str.match(/"id"\s*:\s*"([^"]+)"/);
  accountId = match ? match[1] : null;
}
if (!accountId) throw new Error('Failed to extract account ID from JT response');

// Merge with previous data from Extract node
const extractData = $('Extract & Validate').first().json;
return [{ json: { ...extractData, jt_account_id: accountId } }];

const prev = $input.first().json;
let contactId;
try {
  const result = typeof prev.result === 'string' ? JSON.parse(prev.result) : prev.result;
  contactId = result?.createContact?.id || result?.id;
} catch(e) {
  const str = JSON.stringify(prev);
  const match = str.match(/"id"\s*:\s*"([^"]+)"/);
  contactId = match ? match[1] : null;
}
const extractData = $('Parse Account ID').first().json;
return [{ json: { ...extractData, jt_contact_id: contactId || 'unknown' } }];

const prev = $input.first().json;
let jobId;
try {
  const result = typeof prev.result === 'string' ? JSON.parse(prev.result) : prev.result;
  jobId = result?.createJob?.id || result?.id;
} catch(e) {
  const str = JSON.stringify(prev);
  const match = str.match(/"id"\s*:\s*"([^"]+)"/);
  jobId = match ? match[1] : null;
}
const extractData = $('Parse Contact ID').first().json;
return [{ json: { ...extractData, jt_job_id: jobId || 'unknown' } }];

// Google Calendar event creation
// Only runs if preferred_date is set
const data = $input.first().json;
if (!data.preferred_date) {
  return [{ json: { ...data, gcal_event_id: null, gcal_skipped: true } }];
}

// Map preferred_time to hour
const timeMap = { morning: '09:00', afternoon: '13:00', evening: '17:00' };
const startTime = timeMap[data.preferred_time] || '09:00';
const dateStr = data.preferred_date; // YYYY-MM-DD
const startDateTime = `${dateStr}T${startTime}:00`;

// End time = 15 min later
const [h, m] = startTime.split(':').map(Number);
const endMin = m + 15;
const endH = h + Math.floor(endMin / 60);
const endM = endMin % 60;
const endTime = `${String(endH).padStart(2,'0')}:${String(endM).padStart(2,'0')}`;
const endDateTime = `${dateStr}T${endTime}:00`;

return [{
  json: {
    ...data,
    gcal_summary: `📞 ${data.contact_name} — ${data.calc_label} (calculator lead)`,
    gcal_description: data.job_description + '\n\nReport: ' + data.report_url,
    gcal_start: startDateTime,
    gcal_end: endDateTime,
    gcal_timezone: 'America/Denver'
  }
}];

// Send email via SMTP
// This node prepares the email content
// If SMTP isn't configured, this is a no-op
const data = $('Extract & Validate').first().json;

const html = `<div style="font-family: 'Helvetica Neue', Arial, sans-serif; max-width: 520px; color: #23282d;">
  <p>Hi ${data.first_name},</p>
  <p>Here's your project summary based on the selections you made:</p>
  <p style="font-size: 20px; font-weight: bold;">Estimated range: $${(data.estimate_low || 0).toLocaleString()} – $${(data.estimate_high || 0).toLocaleString()}</p>
  <p><a href="${data.report_url}" style="display: inline-block; padding: 12px 24px; background: #cf995f; color: white; text-decoration: none; border-radius: 8px; font-weight: 600;">View your project summary →</a></p>
  <p style="color: #6b7280; font-size: 14px;">These numbers are based on real Heartwood Craft projects in the Gallatin Valley. I'll follow up within the hour to discuss your project and answer any questions.</p>
  <p>— Eric<br>Heartwood Craft<br>406-551-5061</p>
</div>`;

return [{
  json: {
    ...data,
    email_to: data.contact_email,
    email_subject: `Your ${data.calc_label} project summary — Heartwood Craft`,
    email_html: html
  }
}];
